mapper.update:
UPDATE userCart c 
SET c.quantity = c.quantity - 1,
    c.updatedAt = NOW()
WHERE c.cartSeq = #{cartSeq} 
    AND c.productSeq = #{productSeq}
    AND c.quantity  >  1

UPDATE userCart c
    JOIN stock s 
    ON c.productSeq = s.productSeq 
SET c.quantity = #{quantity},
    c.updatedAt = NOW()
WHERE c.cartSeq = #{cartSeq}
	AND c.productSeq = #{productSeq}
	AND s.quantity  >   #{quantity}

mapper.delete:
DELETE FROM userCart
WHERE cartSeq = #{cartSeq}
    AND productSeq = #{productSeq}
